raw_pred_sql:
SELECT name, amenity 
FROM campus_places 
WHERE name IS NOT NULL AND name != 'nan' AND (amenity ILIKE '%library%');

SELECT name, amenity 
FROM campus_places 
WHERE name IS NOT NULL AND name != 'nan' AND (amenity ILIKE '%restaurant%');

SELECT * 
FROM campus_places 
WHERE name IS NOT NULL AND name != 'nan' AND amenity != 'school';

WITH junior AS (
  SELECT 'Young person looking for something quick to eat.' as context
), tags AS (
  SELECT * FROM campus_places WHERE amenity ILIKE '%fast_food%' OR "takeaway" = 'yes' AND name IS NOT NULL AND name != 'nan'
)
SELECT element, id, name, short_name, official_name, alt_name, name_en, name_hi, geometry
FROM tags
WHERE ST_DWithin(geometry::geography, (SELECT geometry::geography FROM campus_places WHERE name ILIKE '%junior hostel%'), 500)
ORDER BY ST_Distance(geometry::geography, (SELECT geometry::geography FROM campus_places WHERE name ILIKE '%junior hostel%')) ASC
LIMIT 5;
